const body = $input.first().json.body || $input.first().json;
const invoice = body.data?.object || body;
const email = invoice.customer_email || '';
const name = invoice.customer_name || '';
const amount = ((invoice.amount_due || 0) / 100).toFixed(2);
const nextAttempt = invoice.next_payment_attempt ? new Date(invoice.next_payment_attempt * 1000).toLocaleDateString() : 'soon';
const customerId = invoice.customer || '';

return [{ json: { email, name: name || 'there', amount, nextAttempt, customerId, attempt: 1 } }];
